const seed = $node.Webhook.json.body.seed_keyword;
const discId = $node.Webhook.json.body.discovery_id;
const cbUrl = $node.Webhook.json.body.callback_url;

// Parse response — n8n returns it as {data: "[...json string...]"}
let baseSuggestions = [];
try {
  const raw = $input.first().json;
  let parsed;

  if (typeof raw.data === 'string') {
    // Response is a JSON string inside .data
    parsed = JSON.parse(raw.data);
  } else if (Array.isArray(raw.data)) {
    parsed = raw.data;
  } else if (Array.isArray(raw)) {
    parsed = raw;
  } else if (raw['1']) {
    baseSuggestions = Array.isArray(raw['1']) ? raw['1'] : [];
  }

  if (parsed && Array.isArray(parsed) && parsed.length >= 2) {
    baseSuggestions = parsed[1] || [];
  }
} catch(e) {
  return [{json: {discovery_id: discId, callback_url: cbUrl, ideas: [], debug: e.message}}];
}

// Normalize and score
function norm(t) {
  return t.replace(/\u0643/g,'\u06A9').replace(/\u064A/g,'\u06CC')
          .replace(/[\u064B-\u065F]/g,'').replace(/\u200C{2,}/g,'\u200C').replace(/\s+/g,' ').trim();
}
const stops = new Set(['و','در','به','از','که','این','را','با','است','آن','یک','برای','تا','ها','های','می','شود']);
function score(kw) {
  const sw = seed.split(/[\s\u200C]+/).filter(w => !stops.has(w));
  const kws = kw.split(/[\s\u200C]+/).filter(w => !stops.has(w));
  let m = 0;
  sw.forEach(s => { if (kws.some(k => k.includes(s) || s.includes(k))) m++; });
  return Math.min(100, Math.round((sw.length ? m/sw.length : 0.5) * 100) + Math.min(20, kws.length * 5));
}
function isQ(t) { return t.includes('\u061F') || ['چیست','چگونه','چرا','کجا','آیا','کدام'].some(q => t.includes(q)); }

const all = new Map();
baseSuggestions.forEach(kw => {
  if (typeof kw !== 'string') return;
  const n = norm(kw);
  if (n.length < 3) return;
  const key = n.toLowerCase().replace(/\u200C/g, ' ');
  if (key === seed.toLowerCase().replace(/\u200C/g, ' ')) return;
  all.set(key, {keyword: n, source: 'suggest', relevance: score(n), is_question: isQ(n)});
});

const ideas = Array.from(all.values()).sort((a,b) => b.relevance - a.relevance).slice(0, 200);
return [{json: {discovery_id: discId, callback_url: cbUrl, ideas}}];
